svg.script:
const NS = 'http://www.w3.org/2000/svg';
const cell = 70;
function n(v, d=0) { const x = parseInt(v, 10); return Number.isFinite(x) ? x : d; }
function make(tag, attrs = {}, text = null) {
  const el = document.createElementNS(NS, tag);
  Object.entries(attrs).forEach(([k,v]) => el.setAttribute(k, String(v)));
  if (text !== null) el.textContent = text;
  return el;
}
function parsePairs(raw) {
  const out = new Set();
  const re = /\(?\s*(\d+)\s*\|->\s*(\d+)\s*\)?/g;
  let m;
  while ((m = re.exec(raw || '')) !== null) out.add(`${m[1]},${m[2]}`);
  return out;
}
function actionName(a) {
  return ({0:'none', 1:'left', 2:'down', 3:'right', 4:'up'}[a] || '?');
}
function render() {
  const scene = document.getElementById('scene');
  const board = document.getElementById('board');
  if (!scene || !board) return;
  while (board.firstChild) board.removeChild(board.firstChild);
  const maxX = n(scene.getAttribute('data-maxx'), 3);
  const maxY = n(scene.getAttribute('data-maxy'), 3);
  const agentX = n(scene.getAttribute('data-agentx'), 0);
  const agentY = n(scene.getAttribute('data-agenty'), maxY);
  const startX = n(scene.getAttribute('data-startx'), 0);
  const startY = n(scene.getAttribute('data-starty'), maxY);
  const goalX = n(scene.getAttribute('data-goalx'), maxX);
  const goalY = n(scene.getAttribute('data-goaly'), 0);
  const holes = parsePairs(scene.getAttribute('data-holes'));
  const fallen = n(scene.getAttribute('data-fallen'), 0);
  const reached = n(scene.getAttribute('data-reached'), 0);
  const done = n(scene.getAttribute('data-done'), 0);
  const lastAction = n(scene.getAttribute('data-last-action'), 0);
  const reward = scene.getAttribute('data-reward');
  const width = (maxX + 1) * cell;
  const height = (maxY + 1) * cell;
  const svg = document.documentElement;
  svg.setAttribute('viewBox', `0 0 ${width + 120} ${height + 180}`);
  svg.setAttribute('width', width + 120);
  svg.setAttribute('height', height + 180);
  board.appendChild(make('rect', {x:0,y:0,width,height,fill:'#fafafa',stroke:'#222','stroke-width':2}));
  for (let y = 0; y <= maxY; y++) {
    for (let x = 0; x <= maxX; x++) {
      const sx = x * cell, sy = (maxY - y) * cell, key = `${x},${y}`;
      let fill = '#dff7ff', label = 'F', textFill = '#245';
      if (holes.has(key)) { fill = '#1f2937'; label = 'H'; textFill = 'white'; }
      if (x === startX && y === startY) { fill = '#dff0d8'; label = 'S'; textFill = '#246b2f'; }
      if (x === goalX && y === goalY) { fill = '#fff2b3'; label = 'G'; textFill = '#7d6608'; }
      board.appendChild(make('rect', {x:sx,y:sy,width:cell,height:cell,fill,stroke:'#999','stroke-width':1}));
      board.appendChild(make('text', {x:sx+cell/2,y:sy+29,'text-anchor':'middle','font-family':'Arial','font-size':22,'font-weight':'bold',fill:textFill}, label));
      board.appendChild(make('text', {x:sx+8,y:sy+62,'font-family':'Arial','font-size':11,fill:'#777'}, `${x},${y}`));
    }
  }
  const ax = agentX * cell + cell/2;
  const ay = (maxY - agentY) * cell + cell/2 + 12;
  const agentFill = reached ? '#2ca02c' : fallen ? '#e74c3c' : '#1f77b4';
  board.appendChild(make('circle', {cx:ax,cy:ay,r:17,fill:agentFill,stroke:'#0b3558','stroke-width':3}));
  board.appendChild(make('text', {x:ax,y:ay+5,'text-anchor':'middle','font-family':'Arial','font-size':13,'font-weight':'bold',fill:'white'}, 'A'));
  const status = document.getElementById('txt_status');
  if (status) {
    status.setAttribute('y', height + 95);
    status.textContent = `reward=${reward} | done=${done} | reached=${reached} | fallen=${fallen} | action=${actionName(lastAction)}`;
  }
  const legend = document.getElementById('txt_legend');
  if (legend) legend.setAttribute('y', height + 120);
}
const observer = new MutationObserver(render);
observer.observe(document.getElementById('scene'), { attributes: true });
render();
